import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as c}from"./nyalra_no_mono-8344e451.js";import{_ as p,W as i,X as s,Y as _,Z as e,$ as t,a1 as o,a2 as d,a0 as m,C as a}from"./framework-91490e6a.js";const f={},g=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),u={href:"https://tree-novel.com/works/episode/9c087751f4bd968de951be442da870d8.html",target:"_blank",rel:"noopener noreferrer"},b=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),h=m('<hr><p>最近，我改装了Game Boy Advance（GBA）。我更换了外壳，将液晶屏幕更换成了IPS屏幕，这使得画质更高，而且更亮。</p><figure><img src="https://img.tree-novel.com/talk/5ac2ce800ac9de72388180bfef6d617f.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>GBA可以瞬间启动并且马上就可以玩游戏，这真的很棒。我最近最喜欢的游戏是『もじぴったん（Mojipittan）』。这是一个将单词连在一起做成连锁或填充单元格的游戏。もじぴったん，适度的大脑体操和游戏的快感让人心情愉悦，非常棒。在GBA上，就像『リズム天国（节奏天国）』和『メイドインワリオ（瓦里奥制造）』一样，简单的操作连贯进行，直接迎合了直观的「快乐」感觉，非常有游戏性。</p><p>我认为，游戏的终极目标是使人「愉悦」。不论是动作游戏还是射击游戏，当然，有时由于难度而无法完成，也可能让你感到不悦和沮丧，但这正是为了在战胜强敌后获得的愉悦感。虽然敌人的强大和挑战是能够容忍的，但单纯的操作性差或系统复杂等因素只会给游戏减分。按下按钮后，顺畅地执行某种动作，然后通过这些动作改变情境，这才有趣。游戏无论做到什么程度，都是基于「婴儿连按会发出愉快声音的玩具」这种原始的喜悦的不断延伸。</p><p>这不仅适用于动作类游戏，还适用于随着故事情节的推进，增减数字以及调整角色的好感度。例如拙作『NEEDY GIRL OVERDOSE』，当超天酱进行直播时，通过现实中不可能实现的数字的戏剧性增减，逐渐显现出她的未来，给作为「阿P」的玩家以糖糖（小雨）的反应的变化作为「奖励」。对于以文本为主的游戏，故事情节上的负荷不一定会让人感到不悦，而其中的心跳感、刺激和悲伤也可以成为「奖励」。这才是有趣之处。但是，点击哪里会实现如何操作的「操作性」绝对越舒服越好。这方面，我们的程序员とりい倾注了巨大的努力。</p><p>虽然稍微有点偏离话题，总之，（好的）游戏应该让玩家感到愉快并提供新的体验。从这个意义上讲，前面提到的三款GBA游戏『Mojipittan』、『瓦里奥制造』和『节奏天国』等都非常出色。一旦开始游戏，就可以立即开始操作（这是复古便携游戏机的优点），伴随着欢快的音乐，玩家通过不断通关，提高操作灵敏度，渐渐地复杂的动作也可以自然而然地完成。按下按钮就能立即看到结果，这种感觉使人能够体会到自己的操作技巧在增长。将这个经验与故事情节、庞大的地图以及更复杂但理解后带来极大愉悦感的系统相结合，就变成了一部大制作游戏。</p><p>大作既然是大作，当然有其独特的体验，但游戏的本质在于「触摸时的愉悦感」，因此启动GBA，迅速进行大脑和手指的锻炼，只需专注于操作约30分钟到一小时，您就可以忘记所有杂念，这很接近于禅修。大型游戏需要复杂的思考和故事情节，这会让各种信息充斥头脑，因此才如此有趣。但有时，我们也希望更即时地逃离现实。像『Mojipittan』这样的游戏，不同于动作游戏，更像是通过联想单词来展示语言能力，这会让大脑愉悦地进行适度的锻炼。这是一款出色的游戏。</p><p>如果我在制作『Need Girl Overdose』之后继续制作游戏，那么像「单纯的操作令人愉快」这样贴近游戏本质的游戏对我来说几乎是不可能的。因为我必须从想要编写的文本中反过来设计游戏，所以「阅读文字 = 在游戏中等待操作的浪费时间的停顿」难免会插入其中。这就导致动作与文字的结合并不流畅，我也不具备将这两者融合成令人愉快的游戏体验的能力。就像『节奏天国』的制作人「つんく♂」所说的，「所谓的音游仅仅是目押，我想创造一个能让玩家真正感受到节奏的游戏」（意思如此），这是他的愿望，也是他的构思（真的是很了不起的话），他的构思中，涉及到「节奏」和「动作」，是我不能理解的领域。</p><p>能够玩上数十小时并在通关时获得爽快感和满足感是宝贵的体验，但与此同时，也有为了「现实逃避」而持续研究简单操作的团队。久违地触碰了GBA，我重新确认了后者的愉悦感，真是沉溺于童心的夏天。</p><hr><p><img src="'+c+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/6942fa8c3ba6febbde6472332952cd3b.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【Game Boy Advance IPS液晶】这是一台经过各种改造的Game Boy Advance。改造似乎过于适合男孩子了。更换零部件和增强零部件的存在，即使成年后也会让人感到兴奋吧。</p></blockquote>',13);function k(B,y){const n=a("ExternalLinkIcon"),r=a("RouterLink");return i(),s("div",null,[_(" more "),g,e("p",null,[t("原文链接："),e("a",u,[t("第31回／ゲームの本質"),o(n)])]),e("blockquote",null,[b,e("p",null,[o(r,{to:"/posts/Translate/nyalra_kb_30.html"},{default:d(()=>[t("【奈亚拉面壁自语】第30回｜努力与品味之间的残酷差距【230613】")]),_:1})])]),h])}const A=p(f,[["render",k],["__file","nyalra_kb_31.html.vue"]]);export{A as default};
